// Parse and validate the incoming form data
const input = $input.first().json;
let formData = input.body || input;

// When sent as text/plain with no-cors, body arrives as a JSON string
if (typeof formData === 'string') {
  try { formData = JSON.parse(formData); } catch(e) { /* keep as-is */ }
}

const extractField = (data, fieldName) => {
  if (data[`contact[${fieldName}]`]) return data[`contact[${fieldName}]`];
  if (data[fieldName]) return data[fieldName];
  if (data.contact && data.contact[fieldName]) return data.contact[fieldName];
  const camel = fieldName.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
  if (camel !== fieldName && data[camel]) return data[camel];
  return null;
};

const formatPhoneNumber = (phone) => {
  if (!phone) return null;
  let cleaned = phone.replace(/[^\d+]/g, '');
  if (!cleaned || cleaned.replace(/\+/g, '').length === 0) return null;
  if (cleaned.startsWith('0') && cleaned.length === 11) {
    cleaned = '+44' + cleaned.substring(1);
  } else if (cleaned.startsWith('44') && cleaned.length === 12) {
    cleaned = '+' + cleaned;
  } else if (cleaned.startsWith('+44')) {
  } else if (cleaned.startsWith('+')) {
  } else if (cleaned.length === 10 && !cleaned.startsWith('0')) {
    cleaned = '+44' + cleaned;
  } else if (cleaned.length >= 7 && cleaned.length <= 15) {
    cleaned = '+' + cleaned;
  } else {
    return null;
  }
  const digitsOnly = cleaned.replace('+', '');
  if (digitsOnly.length < 7 || digitsOnly.length > 15) return null;
  if (!/^\+\d{7,15}$/.test(cleaned)) return null;
  return cleaned;
};

// Common fields
const name = extractField(formData, 'name');
const email = extractField(formData, 'email');
const phone = extractField(formData, 'phone');
const message = extractField(formData, 'body');
const company = extractField(formData, 'company');
const isCorporate = !!company;

// Device fields
const deviceType = extractField(formData, 'device_type');
const deviceModel = extractField(formData, 'device_model');
const faultArea = extractField(formData, 'fault_area');

// Corporate fields
const jobTitle = extractField(formData, 'job_title');
const fleetSize = extractField(formData, 'fleet_size');
const sla = extractField(formData, 'sla');
const interestedDevices = extractField(formData, 'interested_devices');
const tags = extractField(formData, 'tags');

// Quote wizard fields
const source = extractField(formData, 'source');
const repairTitle = extractField(formData, 'repair_title');
const issue = extractField(formData, 'issue');
const route = extractField(formData, 'route');
const isQuoteEmail = (source === 'quote-wizard-email-quote');

// Pricing breakdown (from wizard DOM)
const basePrice = extractField(formData, 'base_price');
const expressName = extractField(formData, 'express_name');
const expressMeta = extractField(formData, 'express_meta');
const expressPrice = extractField(formData, 'express_price');
const serviceName = extractField(formData, 'service_name');
const servicePrice = extractField(formData, 'service_price');
const totalPrice = extractField(formData, 'total_price');
const turnaround = extractField(formData, 'turnaround');
const estimatesRaw = extractField(formData, 'estimates');
const warranty = extractField(formData, 'warranty');
const parts = extractField(formData, 'parts');
const productUrl = extractField(formData, 'productUrl');
const deviceColor = extractField(formData, 'deviceColor');

// Legacy fallbacks for price/turnaround/serviceType
const legacyPrice = extractField(formData, 'price');
const legacyTurnaround = extractField(formData, 'turnaround');
const legacyServiceType = extractField(formData, 'service_type');

// Parse estimates JSON
let estimates = [];
if (estimatesRaw) {
  try { estimates = JSON.parse(estimatesRaw); } catch(e) {}
}

// Validation
if (!email) throw new Error('Email is required');
if (!isQuoteEmail && !name) throw new Error('Name is required');
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email.trim())) throw new Error('Invalid email format');
const formattedPhone = formatPhoneNumber(phone);
const uniqueId = Date.now();

// Build email subject and body for non-quote paths
let subject = '';
let body = '';
if (isCorporate) {
  subject = `Corporate Enquiry: ${company || name} [${uniqueId}]`;
  body = `New corporate enquiry from ${name}`;
  if (company) body += ` at ${company}`;
  body += `\n\nEmail: ${email}\nPhone: ${formattedPhone || 'Not provided'}`;
  if (jobTitle) body += `\nJob Title: ${jobTitle}`;
  if (fleetSize) body += `\nFleet Size: ${fleetSize}`;
  if (sla) body += `\nSLA: ${sla}`;
  if (interestedDevices) body += `\nInterested Devices: ${interestedDevices}`;
  if (message) body += `\n\nMessage:\n${message}`;
} else {
  subject = `Contact Form: ${name} - ${deviceModel || deviceType || 'Repair Enquiry'} [${uniqueId}]`;
  body = `New enquiry from ${name}\n\nEmail: ${email}\nPhone: ${formattedPhone || 'Not provided'}`;
  if (deviceType) body += `\nDevice: ${deviceType}`;
  if (deviceModel) body += ` - ${deviceModel}`;
  if (faultArea) body += `\nFault Area: ${faultArea}`;
  if (message) body += `\n\nMessage:\n${message}`;
}

return {
  json: {
    name: name ? name.trim() : (email ? email.split('@')[0] : 'Quote Request'),
    email: email.trim().toLowerCase(),
    phone: formattedPhone,
    deviceType: deviceType || null,
    deviceModel: deviceModel || null,
    faultArea: faultArea || null,
    message: message || '',
    company: company || null,
    jobTitle: jobTitle || null,
    fleetSize: fleetSize || null,
    sla: sla || null,
    interestedDevices: interestedDevices || null,
    tags: tags || null,
    isCorporate,
    emailSubject: subject,
    emailBody: body,
    uniqueId,
    timestamp: new Date().toISOString(),
    source: source || null,
    repairTitle: repairTitle || null,
    issue: issue || null,
    route: route || null,
    isQuoteEmail,
    // Pricing breakdown
    basePrice: parseFloat(basePrice) || parseFloat(legacyPrice) || 0,
    expressName: expressName || null,
    expressMeta: expressMeta || null,
    expressPrice: parseFloat(expressPrice) || 0,
    serviceName: serviceName || legacyServiceType || 'Walk-in',
    servicePrice: parseFloat(servicePrice) || 0,
    totalPrice: totalPrice || legacyPrice || null,
    turnaround: turnaround || legacyTurnaround || null,
    estimates: estimates,
    warranty: warranty || '2-year warranty',
    parts: parts || 'Genuine Apple parts',
    productUrl: productUrl || null,
    deviceColor: deviceColor || null
  }
};

// Extract the contact ID from Create Consumer Contact response
const contactResponse = $input.first().json;
const formData = $('Parse Form Data').first().json;

let customerContactId = null;

// Case 1: Contact created successfully
if (contactResponse.id) {
  customerContactId = contactResponse.id;
}

// Case 2: Contact already exists - extract ID from error message
if (!customerContactId && contactResponse.errors) {
  const errorMsg = contactResponse.errors[0]?.message || '';
  const match = errorMsg.match(/id=([a-f0-9]+)/);
  if (match) {
    customerContactId = match[1];
  }
}

if (!customerContactId) {
  throw new Error('Could not get contact ID: ' + JSON.stringify(contactResponse));
}

return {
  json: {
    customerContactId: customerContactId,
    customerEmail: formData.email,
    customerName: formData.name,
    customerPhone: formData.phone,
    emailSubject: formData.emailSubject
  }
};

