// Extract the contact ID from Create Corporate Contact response
const contactResponse = $input.first().json;
const formData = $('Parse Form Data').first().json;

let contactId = null;

// Case 1: Contact created successfully
if (contactResponse.id) {
  contactId = contactResponse.id;
}

// Case 2: Contact already exists - extract ID from error message
if (!contactId && contactResponse.errors) {
  const errorMsg = contactResponse.errors[0]?.message || '';
  const match = errorMsg.match(/id=([a-f0-9]+)/);
  if (match) {
    contactId = match[1];
  }
}

if (!contactId) {
  throw new Error('Could not get corporate contact ID: ' + JSON.stringify(contactResponse));
}

return {
  json: {
    contactId,
    ...formData
  }
};

// Get company ID from response and pass through all data
const companyResponse = $input.first().json;
const prevData = $('Extract Corporate Contact ID').first().json;

let companyId = companyResponse.id || null;

return {
  json: {
    companyId,
    ...prevData
  }
};

// Build the Intercom ticket with all corporate details
const prevData = $('Extract Company ID').first().json;

// Build structured ticket description
const lines = [];
lines.push(`Contact: ${prevData.name}`);
lines.push(`Email: ${prevData.email}`);
lines.push(`Phone: ${prevData.phone || 'Not provided'}`);
lines.push(`Company: ${prevData.company}`);
if (prevData.jobTitle) lines.push(`Job Title: ${prevData.jobTitle}`);
if (prevData.fleetSize) lines.push(`Fleet Size: ${prevData.fleetSize}`);
if (prevData.interestedDevices) lines.push(`Interested Devices: ${prevData.interestedDevices}`);
if (prevData.sla) lines.push(`SLA Preference: ${prevData.sla}`);
if (prevData.message) lines.push(`\nMessage:\n${prevData.message}`);

const ticketDescription = lines.join('\n');
const ticketTitle = `Corporate Enquiry: ${prevData.company}`;

return {
  json: {
    contactId: prevData.contactId,
    companyId: prevData.companyId,
    ticketTitle,
    ticketDescription,
    ...prevData
  }
};

// Build Slack message from all collected data
const prevData = $('Prepare Corporate Ticket').first().json;
const ticketResponse = $input.first().json;
const ticketId = ticketResponse?.ticket_id || ticketResponse?.id || 'N/A';

// Build details as a single-column list
