lines.push(`*Contact:* ${prevData.name}`);
lines.push(`*Email:* ${prevData.email}`);
lines.push(`*Phone:* ${prevData.phone || 'Not provided'}`);
lines.push(`*Role:* ${prevData.jobTitle || 'Not provided'}`);
lines.push(`*Company:* ${prevData.company}`);
lines.push(`*Fleet Size:* ${prevData.fleetSize || 'Not provided'}`);
lines.push(`*Interested Devices:* ${prevData.interestedDevices || 'Not provided'}`);
lines.push(`*SLA Preference:* ${prevData.sla || 'Not provided'}`);
if (prevData.message) {
  lines.push(`*Message:* ${prevData.message}`);
}

const slackBlocks = [
  {
    type: 'header',
    text: {
      type: 'plain_text',
      text: `\u{1F3E2} New Corporate Enquiry: ${prevData.company}`,
      emoji: true
    }
  },
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: lines.join('\n')
    }
