const d = $input.first().json;

const name = d.name || 'there';
const route = d.route || 'repair';
const isDiag = route === 'diagnostic';
const repairTitle = d.repairTitle || 'Repair Quote';
const issue = d.issue || '';
const deviceType = d.deviceType || '';
const deviceModel = d.deviceModel || '';
const device = deviceModel ? (deviceType + ' \u2014 ' + deviceModel) : (deviceType || '-');
const fault = d.faultArea || '-';
const warranty = d.warranty || '2-year warranty';
const parts = d.parts || 'Genuine Apple parts';
const deviceColor = d.deviceColor || null;
const productUrl = d.productUrl || 'https://www.icorrect.co.uk/#home-contact';

// Product page URL for CTA

// Prices — handle BOTH old wizard (price:"£898") and new wizard (basePrice:799)
const basePrice = parseFloat(d.basePrice) || 0;
const expressPrice = parseFloat(d.expressPrice) || 0;
const servicePrice = parseFloat(d.servicePrice) || 0;
const serviceName = d.serviceName || d.serviceType || 'Walk-in';

// Total price: from new wizard or old wizard
const rawTotal = d.totalPrice || d.price || '';
// Strip £ to get numeric total
const numericTotal = parseFloat(String(rawTotal).replace(/[^0-9.]/g, '')) || 0;
// If we have add-ons, base is from basePrice. Otherwise use total.
const hasAddOns = expressPrice > 0 || servicePrice > 0;
const displayBase = basePrice > 0 ? basePrice : numericTotal;
const displayTotal = numericTotal || (basePrice + expressPrice + servicePrice);

const fmtP = (v) => {
  const n = parseFloat(v);
  if (isNaN(n) || n === 0) return null;
  return '\u00a3' + (n % 1 === 0 ? n.toString() : n.toFixed(2));
};

// Hardcoded turnaround
const TA = {
  repair:     { iPhone: '2-4 hours', MacBook: '2-3 working days', iPad: '2-3 working days', 'Apple Watch': '2-3 working days' },
  diagnostic: { iPhone: '2 working days', MacBook: '2 working days', iPad: '2 working days', 'Apple Watch': '2 working days' }
};
const turnaround = (isDiag ? TA.diagnostic : TA.repair)[deviceType] || (isDiag ? '2 working days' : '2-3 working days');

// Parse estimates
let estimates = d.estimates || [];
if (typeof estimates === 'string') {
  try { estimates = JSON.parse(estimates); } catch(e) { estimates = []; }
}

// Badge
const badgeBg = isDiag ? '#fffbeb' : '#ecfdf5';
const badgeColor = isDiag ? '#92400e' : '#065f46';
const badgeText = isDiag ? 'Diagnostic required' : 'We can fix this';
const badgeIcon = isDiag ? '\uD83D\uDD0D' : '\u2705';

// Big price: show BASE when breakdown exists, TOTAL when not
const bigPrice = hasAddOns && basePrice > 0 ? fmtP(basePrice) : (fmtP(displayBase) || 'TBC');

// Diagnostic estimates
let estimatesHtml = '';
if (isDiag && estimates.length > 0) {
  let rows = '';
  for (const est of estimates) {
    rows += `<div style="display: flex; justify-content: space-between; padding: 6px 0; font-size: 13px;">
      <span style="color: #4b5563;">${est.label}</span>
      <span style="color: #111827; font-weight: 600;">${est.value}</span>
    </div>`;
  }
  estimatesHtml = `<div style="background: #f8f9fb; border: 1px solid #e5e7eb; border-radius: 8px; padding: 14px 16px; margin: 0 20px 16px;">${rows}</div>`;
}

// Cost breakdown (only when we have add-on data from new wizard)
let breakdownHtml = '';
if (hasAddOns && basePrice > 0) {
  let rows = '';
  const baseLabel = isDiag ? 'Diagnostic' : (repairTitle.length > 40 ? 'Repair' : repairTitle);
  rows += `<tr style="border-bottom: 1px solid #f3f4f6;">
    <td style="padding: 12px 20px; color: #111827; font-weight: 600; font-size: 14px;">${baseLabel}</td>
    <td style="padding: 12px 20px; color: #111827; font-weight: 600; font-size: 14px; text-align: right;">${fmtP(basePrice)}</td>
  </tr>`;
  if (expressPrice > 0) {
    rows += `<tr style="border-bottom: 1px solid #f3f4f6;">
      <td style="padding: 12px 20px; color: #111827; font-weight: 500; font-size: 14px;">${d.expressName || 'Express turnaround'}</td>
      <td style="padding: 12px 20px; color: #111827; font-weight: 600; font-size: 14px; text-align: right;">+${fmtP(expressPrice)}</td>
    </tr>`;
  }
  if (servicePrice > 0) {
    rows += `<tr style="border-bottom: 1px solid #f3f4f6;">
      <td style="padding: 12px 20px; color: #111827; font-weight: 500; font-size: 14px;">${serviceName}</td>
      <td style="padding: 12px 20px; color: #111827; font-weight: 600; font-size: 14px; text-align: right;">+${fmtP(servicePrice)}</td>
    </tr>`;
  }
  rows += `<tr>
    <td style="padding: 16px 20px; color: #111827; font-weight: 700; font-size: 16px;">Total</td>
    <td style="padding: 16px 20px; color: #111827; font-weight: 700; font-size: 20px; text-align: right;">${fmtP(displayTotal)}</td>
  </tr>`;
  breakdownHtml = `<div style="border-top: 1px solid #e5e7eb;"><table style="width: 100%; border-collapse: collapse;">${rows}</table></div>`;
}

const emailSubject = 'Your iCorrect Repair Quote: ' + (deviceModel || repairTitle);

const html = `<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 0; background-color: #ffffff;">
  <div style="text-align: center; padding: 32px 24px 24px; border-bottom: 1px solid #e5e7eb;">
    <h1 style="margin: 0; font-size: 26px; font-weight: 700; color: #000000; letter-spacing: -0.02em;">iCorrect</h1>
    <p style="margin: 6px 0 0; color: #6b7280; font-size: 13px; font-weight: 500; letter-spacing: 0.02em;">Apple Microelectronics Repair Specialists</p>
  </div>
  <div style="padding: 32px 24px;">
    <p style="font-size: 16px; color: #111827; margin: 0 0 6px;">Hi ${name},</p>
    <p style="font-size: 15px; color: #4b5563; margin: 0 0 28px; line-height: 1.5;">Here's your repair quote. This is valid for 30 days.</p>
    <div style="background: #f9fafb; border: 1px solid #e5e7eb; border-radius: 12px; overflow: hidden; margin-bottom: 28px;">
      <div style="padding: 14px 20px; background: ${badgeBg}; border-bottom: 1px solid #e5e7eb;">
        <span style="font-size: 12px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.05em; color: ${badgeColor};">${badgeIcon} ${badgeText}</span>
      </div>
      <div style="padding: 20px 20px 0;">
        <h2 style="margin: 0 0 8px; font-size: 18px; font-weight: 700; color: #111827; line-height: 1.3;">${repairTitle}</h2>
        ${issue ? '<p style="margin: 0 0 16px; font-size: 14px; color: #6b7280; line-height: 1.5;">' + issue + '</p>' : ''}
      </div>
      <div style="padding: 0 20px 16px;">
        <span style="font-size: 12px; color: #9ca3af; font-weight: 500;">${hasAddOns ? 'From' : 'From'}</span>
        <div style="font-size: 32px; font-weight: 700; color: #111827; letter-spacing: -0.02em;">${bigPrice}</div>
      </div>
      ${estimatesHtml}
      ${breakdownHtml}
      <table style="width: 100%; border-collapse: collapse; font-size: 14px; border-top: 1px solid #e5e7eb;">
        <tr style="border-bottom: 1px solid #f3f4f6;">
          <td style="padding: 14px 20px; color: #6b7280; font-weight: 500; width: 120px;">Device</td>
          <td style="padding: 14px 20px; color: #111827; font-weight: 600;">${device}</td>
        </tr>
        ${deviceColor ? '<tr style="border-bottom: 1px solid #f3f4f6;"><td style="padding: 14px 20px; color: #6b7280; font-weight: 500;">Colour</td><td style="padding: 14px 20px; color: #111827; font-weight: 600;">' + deviceColor + '</td></tr>' : ''}
        <tr style="border-bottom: 1px solid #f3f4f6;">
          <td style="padding: 14px 20px; color: #6b7280; font-weight: 500;">Fault</td>
          <td style="padding: 14px 20px; color: #111827; font-weight: 600;">${fault}</td>
        </tr>
        <tr style="border-bottom: 1px solid #f3f4f6;">
          <td style="padding: 14px 20px; color: #6b7280; font-weight: 500;">Turnaround</td>
          <td style="padding: 14px 20px; color: #111827; font-weight: 600;">${turnaround}</td>
        </tr>
        <tr style="border-bottom: 1px solid #f3f4f6;">
          <td style="padding: 14px 20px; color: #6b7280; font-weight: 500;">Service</td>
          <td style="padding: 14px 20px; color: #111827; font-weight: 600;">${serviceName}</td>
        </tr>
        <tr style="border-bottom: 1px solid #f3f4f6;">
          <td style="padding: 14px 20px; color: #6b7280; font-weight: 500;">Warranty</td>
          <td style="padding: 14px 20px; color: #111827; font-weight: 600;">${warranty}</td>
        </tr>
        <tr>
          <td style="padding: 14px 20px; color: #6b7280; font-weight: 500;">Parts</td>
          <td style="padding: 14px 20px; color: #111827; font-weight: 600;">${parts}</td>
        </tr>
      </table>
    </div>
    <div style="text-align: center; margin: 0 0 28px;">
      <a href="${productUrl}" style="display: inline-block; background-color: #2563eb; color: #ffffff; padding: 14px 36px; text-decoration: none; border-radius: 8px; font-size: 15px; font-weight: 700; letter-spacing: -0.01em;">Book Your Repair</a>
    </div>
    <div style="background: #f0f9ff; border: 1px solid #bfdbfe; border-radius: 8px; padding: 16px 20px; margin-bottom: 24px;">
      <p style="margin: 0 0 4px; font-size: 13px; font-weight: 700; color: #1e40af;">Walk-in or Collection &amp; Delivery</p>
      <p style="margin: 0; font-size: 13px; color: #3b82f6; line-height: 1.5;">12 Margaret Street, Audley House, London W1W 8JQ<br>Mon-Thu 9am-6pm \u00b7 Fri 10am-6pm \u00b7 +44 (0)207 099 8517</p>
    </div>
    <p style="font-size: 14px; color: #6b7280; line-height: 1.5; margin: 0;">Questions? Simply reply to this email and we'll get back to you.</p>
  </div>
  <div style="border-top: 1px solid #e5e7eb; padding: 24px; text-align: center;">
    <p style="margin: 0 0 4px; font-size: 12px; color: #9ca3af;">iCorrect \u00b7 Apple Microelectronics Repair Specialists \u00b7 London</p>
    <p style="margin: 0; font-size: 12px;"><a href="https://www.icorrect.co.uk" style="color: #2563eb; text-decoration: none;">www.icorrect.co.uk</a></p>
  </div>
</div>`;

return { json: { ...d, emailHtml: html, emailSubject } };

const resp = $input.first().json;
const formData = $('Parse Form Data').first().json;

let contactId = null;
if (resp.id) {
  contactId = resp.id;
} else if (resp.errors) {
  const msg = (resp.errors[0] || {}).message || '';
  const m = msg.match(/id=([a-f0-9]+)/);
  if (m) contactId = m[1];
}

if (!contactId) return [];

return {
  json: {
    contactId,
    name: formData.name || '',
    email: formData.email || '',
    phone: formData.phone || '',
    deviceType: formData.deviceType || '',
    deviceModel: formData.deviceModel || '',
    faultArea: formData.faultArea || '',
    issue: formData.issue || '',
    repairTitle: formData.repairTitle || '',
    route: formData.route || '',
    totalPrice: formData.totalPrice || ''
  }
};

